import Statistics from './Statistics'

function StatisticsList ({items}) {
  <ul>
    {
      items.map(item => (
        <li key={item.id}>
          <Statistics

            title={item.label}
            stats={item.percentage}    
          /> 
        </li>
      ))
    }
  </ul>
}


export default StatisticsList;
